class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        int count = 0;
        for (int i = left; i <= right; i++) {
            for (int j = 0; j < words[i].length(); j++) {
                if (isVowel(words[i][j]) && isVowel(words[i][words[i].length() - 1])) {
                    count++;
                }
            }
        }
        return count;
    }

    bool isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
};
```

